{"code": "import os

def parse_theta_results(fname):
    with open(fname, 'r') as f:
        lines = f.readlines()

    # Filter blank lines (lines that are empty or only whitespace)
    non_blank = []
    for line in lines:
        if line.strip():  # line has non-whitespace content
            non_blank.append(line)

    if len(non_blank) < 2:
        return {'NLL': None, 'mu_normal': None, 'mu_tumors': [], 'C': [], 'p*': []}

    # Parse header (strip whitespace from header line)
    header = non_blank[0].strip().split('\t')
    header = [h.strip() for h in header]

    # Parse data line - DON'T strip the whole line first, just split by tab
    data = non_blank[1].rstrip('\n').split('\t')
    data = [d.strip() for d in data]

    result = {}

    for i, col_name in enumerate(header):
        if i >= len(data):
            val = ''
        else:
            val = data[i]

        if col_name == 'NLL':
            result['NLL'] = float(val) if val else None

        elif col_name == 'mu':
            if not val:
                result['mu_normal'] = None
                result['mu_tumors'] = []
            else:
                parts = val.split(',')
                result['mu_normal'] = float(parts[0]) if parts[0] else None
                result['mu_tumors'] = [float(p) for p in parts[1:] if p] if len(parts) > 1 else []

        elif col_name == 'C':
            if not val:
                result['C'] = []
            else:
                groups = val.split(':')
                parsed_groups = []
                for g in groups:
                    inner = []
                    for item in g.split(','):
                        item = item.strip()
                        if not item or item.lower() in ('na', '?', '.', 'none', 'n/a', '-'):
                            inner.append(None)
                        else:
                            inner.append(int(item))
                    parsed_groups.append(inner)
                result['C'] = parsed_groups

        elif col_name == 'p*':
            if not val:
                result['p*'] = []
            else:
                groups = val.split(':')
                parsed_groups = []
                for g in groups:
                    inner = []
                    for item in g.split(','):
                        item = item.strip()
                        if not item or item.lower() in ('na', '?', '.', 'none', 'n/a', '-'):
                            inner.append(None)
                        else:
                            inner.append(float(item))
                    parsed_groups.append(inner)
                result['p*'] = parsed_groups

    return result

